  function showPrivateGate(message) {
    document.documentElement.style.visibility = "visible";
    var gate = document.getElementById("privateGate");
    var msg = document.getElementById("privateGateMessage");
    var page = document.getElementById("privatePageContent");
    if (msg) msg.textContent = message || "Este site é privado. Faça login para continuar.";
    if (gate) gate.style.display = "flex";
    if (page) page.style.display = "none";
  }

  function showPrivateContent() {
    document.documentElement.style.visibility = "visible";
    var gate = document.getElementById("privateGate");
    var page = document.getElementById("privatePageContent");
    if (gate) gate.style.display = "none";
    if (page) page.style.display = "block";
  }

  (function enforcePrivateAccess() {
    try {
      document.documentElement.style.visibility = "hidden";

      if (typeof firebase === "undefined") {
        showPrivateGate("Não foi possível carregar a autenticação. Verifique sua conexão e tente novamente.");
        return;
      }

      if (!firebase.apps.length) {
        firebase.initializeApp(firebaseConfig);
      }

      firebase.auth().onAuthStateChanged(function(user) {
        if (user) {
          console.log("Usuário autenticado:", user.email || user.uid);
          showPrivateContent();
        } else {
          showPrivateGate("Acesso restrito. Entre com sua conta para visualizar este conteúdo.");
        }
      });
    } catch (e) {
      console.warn("Firebase auth error:", e.message);
      showPrivateGate("Não foi possível validar a autenticação agora. Tente novamente.");
    }
  })();

  function goToLogin() {
    window.location.href = "https://geotatica.github.io/Plataforma_Dados/login.html?redirect=" + encodeURIComponent("https://geotatica.github.io/Plataforma_Dados/");
  }

  function logout() {
    try {
      if (typeof firebase !== "undefined" && firebase.auth) {
        firebase.auth().signOut().then(function() {
          showPrivateGate("Sessão encerrada. Faça login novamente para continuar.");
        }).catch(function() {
          showPrivateGate("Sessão encerrada. Faça login novamente para continuar.");
        });
      } else {
        showPrivateGate("Sessão encerrada. Faça login novamente para continuar.");
      }
    } catch (e) {
      console.warn("Firebase auth error:", e.message);
      showPrivateGate("Sessão encerrada. Faça login novamente para continuar.");
    }
  }

    function setManuaisTab(tab, btn) {
      document.querySelectorAll('.manuais-panel').forEach(p => p.style.display = 'none');
      document.getElementById('manuais-' + tab).style.display = 'block';
      document.querySelectorAll('[id^="tab-"]').forEach(b => {
        b.style.background = 'rgba(255,255,255,0.82)';
        b.style.color = 'var(--muted)';
        b.style.boxShadow = 'none';
        b.style.fontWeight = '600';
      });
      btn.style.background = 'linear-gradient(135deg,var(--accent1),var(--accent2))';
      btn.style.color = '#fff';
      btn.style.boxShadow = '0 8px 20px rgba(59,44,207,0.18)';
      btn.style.fontWeight = '700';
    }
  

