function numPad(n) {
  return String(n).padStart(2, "0");
}

function escapeHtml(str) {
  return String(str)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;");
}

function normalizarTexto(str) {
  return String(str || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();
}

function obterTextoFonte(source) {
  return normalizarTexto([
    source.name || "",
    source.desc || "",
    source.meta || "",
    (source.topics || []).join(" ")
  ].join(" "));
}

function inferirPaisRef(source) {
  if (source.pais_ref) return source.pais_ref;

  if (source.cat === "br" || source.cat === "estadual" || source.cat === "municipal") {
    return "brasil";
  }

  const texto = obterTextoFonte(source);

  const paises = [
    { key: "estados_unidos", regex: /united states|usa|u\.s\.|new york|los angeles|chicago|california|texas|florida|alaska|nyc|usgs|noaa|nasa/ },
    { key: "canada", regex: /canada|canadense|canadian/ },
    { key: "reino_unido", regex: /reino unido|united kingdom|uk|england|scotland|wales|british/ },
    { key: "mexico", regex: /mexico|mexic|inegi/ },
    { key: "japao", regex: /japao|japan/ },
    { key: "espanha", regex: /espanha|spain|catalunha|catalunya/ },
    { key: "portugal", regex: /portugal/ },
    { key: "italia", regex: /italia|italy/ },
    { key: "alemanha", regex: /alemanha|germany|deutsch/ },
    { key: "holanda", regex: /holanda|netherlands|dutch|paises baixos/ },
    { key: "franca", regex: /franca|france|french/ },
    { key: "nova_zelandia", regex: /nova zelandia|new zealand/ },
    { key: "quenia", regex: /quenia|kenya/ },
    { key: "australia", regex: /australia|queensland/ },
    { key: "singapura", regex: /singapura|singapore/ },
    { key: "india", regex: /india|indiano/ },
    { key: "colombia", regex: /colombia/ },
    { key: "argentina", regex: /argentina/ },
    { key: "chile", regex: /chile/ },
    { key: "peru", regex: /peru/ },
    { key: "uruguai", regex: /uruguai|uruguay/ },
    { key: "paraguai", regex: /paraguai|paraguay/ },
    { key: "bolivia", regex: /bolivia/ },
    { key: "equador", regex: /equador|ecuador/ },
    { key: "venezuela", regex: /venezuela/ },
    { key: "china", regex: /china/ },
    { key: "coreia", regex: /coreia|korea/ },
    { key: "tailandia", regex: /tailandia|thailand/ },
    { key: "vietna", regex: /vietna|vietnam/ },
    { key: "filipinas", regex: /filipinas|philippines/ },
    { key: "nepal", regex: /nepal/ },
    { key: "mongolia", regex: /mongolia/ },
    { key: "turquia", regex: /turquia|turkey/ },
    { key: "israel", regex: /israel/ },
    { key: "arabia_saudita", regex: /arabia saudita|saudi/ },
    { key: "suecia", regex: /suecia|sweden/ },
    { key: "suica", regex: /suica|switzerland|swiss/ },
    { key: "noruega", regex: /noruega|norway/ },
    { key: "finlandia", regex: /finlandia|finland/ },
    { key: "austria", regex: /austria/ },
    { key: "belgica", regex: /belgica|belgium/ },
    { key: "irlanda", regex: /irlanda|ireland/ },
    { key: "polonia", regex: /polonia|poland/ },
    { key: "republica_tcheca", regex: /republica tcheca|czech republic|czech/ },
    { key: "africa_do_sul", regex: /africa do sul|south africa/ },
    { key: "russia", regex: /russia|russian|federacao russa|federation/ },
    { key: "malasia", regex: /malasia|malaysia/ },
    { key: "taiwan", regex: /taiwan/ }
  ];

  for (const pais of paises) {
    if (pais.regex.test(texto)) return pais.key;
  }

  return "all";
}

function inferirEscala(source) {
  const texto = obterTextoFonte(source);
  const paisRef = inferirPaisRef(source);

  if (source.cat === "br") return "brasil";
  if (source.cat === "estadual") return "estadual_br";
  if (source.cat === "municipal") return "municipal_br";

  if (
    /europa|europe|uniao europeia|africa|asia|oceania|america do sul|america central|america do norte|latin america|south america|north america|central america/.test(texto)
  ) {
    return "continente";
  }

  if (
    /province|provincia|state of|county|prefecture|autonomous community|community of|lander|lander|region of|departamento|regiao|metro area|metropolitan/.test(texto)
  ) {
    return "subnacional_exterior";
  }

  if (paisRef !== "all") {
    if (
      /new york|los angeles|chicago|california|texas|florida|alaska|city of|county|province|prefecture|state/.test(texto)
    ) {
      return "subnacional_exterior";
    }
    return "pais";
  }

  if (source.cat === "urban") {
    return "subnacional_exterior";
  }

  return "global";
}

function obterCuradoriaTematica(source) {
  if (source && source.curadoria && source.curadoria.tema) {
    return {
      tema: source.curadoria.tema,
      temas: Array.isArray(source.curadoria.temas) && source.curadoria.temas.length
        ? source.curadoria.temas
        : temasPorTemaPrincipal(source.curadoria.tema)
    };
  }

  const nome = normalizarTexto(source.name || "");
  const texto = obterTextoClassificacao(source);

  const overrides = [
    { regex: /^bdgex exercito brasileiro$/, tema: "intelligence_military", temas: ["defesa_inteligencia", "geociencias_relevo", "planejamento_localizacao"] },
    { regex: /^datasus|^datasus tabnet|^cnes\b|global health observatory|^who gis|^openicpsr|geoportal da saude/, tema: "health", temas: ["sociedade_saude"] },
    { regex: /^embrapa geoportal$|^fao geocatalog$|^fao geonetwork$|^earthstat$/, tema: "farming", temas: ["agricultura_uso_solo"] },
    { regex: /^aneel sigel$|world bank infrastructure|^nasa power$/, tema: "utilities_communication", temas: ["infraestrutura_utilidades"] },
    { regex: /^vgeo dnit$|^ministerio dos transportes geoprocessamento|^onemap singapore$/, tema: "transportation", temas: ["transporte_logistica", "infraestrutura_utilidades"] },
    { regex: /^incra sigef$|^funai terras indigenas$/, tema: "planning_cadastre", temas: ["planejamento_localizacao"] },
    { regex: /^geonames$|^openaddresses$/, tema: "location", temas: ["planejamento_localizacao"] },
    { regex: /^geoboundaries$|^gadm$|^gadm \(global administrative areas\)$|^natural earth data$|^natural earth$|^diva gis$|^eurostat gisco$/, tema: "boundaries", temas: ["planejamento_localizacao"] },
    { regex: /^ana dados abertos$|^snirh ana$|^hydrosheds$|^marine regions$|^fema flood hazard layer$/, tema: "inland_waters", temas: ["clima_oceanos", "planejamento_localizacao"] },
    { regex: /^unep wcmc ocean data$|^global fishing watch$|^copernicus marine service$|^gebco$|^aviso altimetria oceanica$|^noaa ncei$|^noaa coastal geospatial$/, tema: "oceans", temas: ["clima_oceanos"] },
    { regex: /^openaerialmap$|^planet explorer$|^copernicus data space$|^google earth engine$|^radiant earth foundation$/, tema: "imagery_basemaps_earth_cover", temas: ["geociencias_relevo"] },
    { regex: /^opentopography$|^srtm nasa jpl$|^aster gdem$|^copernicus dem$|^merit dem$|^noaa etopo$|^open topo lidar datasets$/, tema: "elevation", temas: ["geociencias_relevo"] },
    { regex: /^geosgb$|^smithsonian global volcanism program$|^usgs earthquake catalog$|^anm geoportal$/, tema: "geoscientific_information", temas: ["geociencias_relevo"] },
    { regex: /^gbif$|^iucn red list spatial data$|^ebird cornell lab$|^global forest watch$|^protected planet wdpa$|^world database on protected areas \(wdpa\)$|^modis ndvi evi usgs$|^nasa gedi$/, tema: "biota", temas: ["preservacao_ambiental"] },
    { regex: /^dados abertos gov\.br$|^inde$|^zenodo$|^figshare$|^dataportals$|^dataportals\.org$|^inspire geoportal$|^open data eu$|^uk data portal$|^portugal dados abertos$|^govdata alemanha$|^datos\.gob\.es$|^dati\.gov\.it$|^open canada$|^kenya open data$|^data\.gov\.au$|^africa open data$|^base dos dados$|^data commons$/, tema: "multitematico", temas: ["multitematico"] },
    { regex: /^openstreetmap$|^geofabrik osm downloads$|^overture maps foundation$/, tema: "multitematico", temas: ["planejamento_localizacao", "infraestrutura_utilidades", "transporte_logistica"] }
  ];

  for (const item of overrides) {
    if (item.regex.test(nome)) return item;
  }

  if (/\b(portal de dados abertos|open data|data portal|cat[aá]logo de dados|catalogo de dados|reposit[oó]rio|diret[oó]rio|spatial data infrastructure|infraestrutura de dados espaciais|geoportal|metadados geograficos|geonetwork)\b/.test(texto)
      && /\b(divers|multipl|varios|v[aá]rios|qualquer area|diferentes areas|diferentes temas|dados espaciais e estatisticos)\b/.test(texto)) {
    return { tema: "multitematico", temas: ["multitematico"] };
  }

  return null;
}

function temasPorTemaPrincipal(temaPrincipal) {
  const mapa = {
    farming: ["agricultura_uso_solo"],
    biota: ["preservacao_ambiental"],
    environment: ["preservacao_ambiental"],
    boundaries: ["planejamento_localizacao"],
    climatology_meteorology_atmosphere: ["clima_oceanos"],
    economy: ["economia_trabalho"],
    elevation: ["geociencias_relevo"],
    geoscientific_information: ["geociencias_relevo"],
    health: ["sociedade_saude"],
    imagery_basemaps_earth_cover: ["geociencias_relevo"],
    intelligence_military: ["defesa_inteligencia"],
    inland_waters: ["clima_oceanos", "planejamento_localizacao"],
    location: ["planejamento_localizacao"],
    multitematico: ["multitematico"],
    oceans: ["clima_oceanos"],
    planning_cadastre: ["planejamento_localizacao"],
    society: ["sociedade_saude"],
    structure: ["infraestrutura_utilidades"],
    transportation: ["transporte_logistica"],
    utilities_communication: ["infraestrutura_utilidades"]
  };
  return mapa[temaPrincipal] || [];
}

function obterTextoClassificacao(source) {
  return normalizarTexto([
    source.name || "",
    source.desc || "",
    source.meta || "",
    source.tag || "",
    source.url || "",
    ...(source.formatos || []),
    ...(source.palavras_chave || [])
  ].join(" "));
}

function pontuarTemasFonte(source) {
  const texto = obterTextoClassificacao(source);
  const score = {
    multitematico: 0,
    clima_oceanos: 0,
    geociencias_relevo: 0,
    preservacao_ambiental: 0,
    agricultura_uso_solo: 0,
    economia_trabalho: 0,
    infraestrutura_utilidades: 0,
    transporte_logistica: 0,
    defesa_inteligencia: 0,
    planejamento_localizacao: 0,
    sociedade_saude: 0
  };

  function add(key, regex, weight = 1) {
    if (regex.test(texto)) score[key] += weight;
  }

  add("multitematico", /portal de dados abertos|open data|data portal|catalogo de dados|cat[aá]logo de dados|reposit[oó]rio|diret[oó]rio|spatial data infrastructure|infraestrutura de dados espaciais|geoportal|metadados geograficos|geonetwork/, 2);
  add("multitematico", /divers(as|os)|multipl(as|os)|varios|v[aá]rios|qualquer area|diferentes areas|diferentes temas|varios conjuntos|v[aá]rios conjuntos|dados geograficos e estatisticos|dados espaciais e estatisticos/, 2);

  add("clima_oceanos", /clima|meteorolog|atmosfer|precipit|chuva|temperatura|vento|umidade|rean[aá]lise|forecast|weather|secas|estiagem|radia[cç][aã]o solar/, 3);
  add("clima_oceanos", /oceano|marinho|costeir|litoral|correntes|mare|salinidade|nivel do mar|pesca|aquicultura|hidrolog|hidrico|rios?|bacias?|lagos?|drenagem|inundac|flood/, 2);

  add("geociencias_relevo", /geologia|geomorf|geodivers|geofis|tecton|minera[cç][aã]o|mineral|pedolog|hidrogeolog|cavernas?|sism|vulca/, 3);
  add("geociencias_relevo", /relevo|topograf|altimet|eleva[cç][aã]o|dem\b|mde\b|mdt\b|lidar|batimetria/, 3);
  add("geociencias_relevo", /imagem|imagery|ortoimagem|ortofoto|mosaico|landsat|sentinel|modis|viirs|satelite/, 1);

  add("preservacao_ambiental", /ambiental|meio ambiente|ecologia|conserva[cç][aã]o|preserva[cç][aã]o|bioma|desmatamento|floresta|vegeta[cç][aã]o|incendios?|restaura[cç][aã]o|areas protegidas|biodiversidade|fauna|flora|especies/, 3);

  add("agricultura_uso_solo", /agricultura|agro|agricol|pecuaria|lavoura|safra|pastagem|solos?|aptid[aã]o agricola|zoneamento agroecologico|uso do solo|land use|land cover|cobertura da terra/, 3);

  add("economia_trabalho", /economia|economico|emprego|trabalho|renda|pib|idhm|mercado|producao|industria|comercio|turismo|setor produtivo|atividade economica/, 3);

  add("infraestrutura_utilidades", /infraestrutura|energia|eletric|saneamento|abastecimento|esgoto|telecom|comunica[cç][aã]o|subestac|transmissao|gas|utilidades|servicos publicos/, 3);

  add("transporte_logistica", /transporte|logistica|rodovia|ferrovia|aeroporto|porto|mobilidade|malha viaria|trafego|transito|hidrovia|navega[cç][aã]o/, 3);

  add("defesa_inteligencia", /defesa|militar|inteligencia|seguranca|exercito|marinha|aeronautica|geoint/, 3);

  add("planejamento_localizacao", /planejamento|cadastro|cadastral|fundiari|zoneamento|parcela|lote|parcelamento|endere[cç]os?|geocodifica[cç][aã]o|localiza[cç][aã]o|toponim|gazetteer|localidades|limites administrativos|divisoes administrativas|fronteiras|setores censitarios|malha/, 3);

  add("sociedade_saude", /saude|hospital|epidemi|doenca|mortalidade|morbidade|educa[cç][aã]o|popula[cç][aã]o|demograf|censo|cultura|vulnerabilidade|refugiados|social/, 3);

  return { texto, score };
}

function inferirTemaPrincipal(source) {
  const curadoria = obterCuradoriaTematica(source);
  if (curadoria?.tema) return curadoria.tema;

  const { texto, score } = pontuarTemasFonte(source);
  const temas = inferirTemasAssociados(source);

  if (temas.includes("multitematico")) return "multitematico";

  if (temas.includes("planejamento_localizacao")) {
    if (/endere[cç]os?|geocodifica[cç][aã]o|toponim|gazetteer|poi|localidades/.test(texto)) return "location";
    if (/limites administrativos|divisoes administrativas|fronteiras|administra[cç][aã]o territorial|setores censitarios|municipios|estados/.test(texto)) return "boundaries";
    return "planning_cadastre";
  }

  if (temas.includes("sociedade_saude")) {
    if (/saude|hospital|epidemi|doenca|mortalidade|morbidade|sanitaria/.test(texto)) return "health";
    return "society";
  }

  if (temas.includes("defesa_inteligencia")) return "intelligence_military";
  if (temas.includes("transporte_logistica")) return "transportation";
  if (temas.includes("infraestrutura_utilidades")) return "utilities_communication";
  if (temas.includes("economia_trabalho")) return "economy";

  if (temas.includes("agricultura_uso_solo")) {
    if (/uso do solo|land use|land cover|cobertura da terra/.test(texto) && !/agricultura|agricol|pecuaria|lavoura|pastagem/.test(texto)) {
      return "imagery_basemaps_earth_cover";
    }
    return "farming";
  }

  if (temas.includes("preservacao_ambiental")) {
    if (/biodiversidade|fauna|flora|especies|areas protegidas|manguezais|recifes/.test(texto)) return "biota";
    return "environment";
  }

  if (temas.includes("clima_oceanos")) {
    if (/oceano|marinho|costeir|correntes|mare|salinidade|nivel do mar|pesca|aquicultura/.test(texto)) return "oceans";
    if (/hidrolog|hidrico|rios?|bacias?|lagos?|drenagem|flood|inundac/.test(texto)) return "inland_waters";
    return "climatology_meteorology_atmosphere";
  }

  if (temas.includes("geociencias_relevo")) {
    if (/imagem|imagery|ortoimagem|ortofoto|mosaico|landsat|sentinel|modis|viirs|satelite|basemap/.test(texto) && !/geologia|minera[cç][aã]o|sism|vulca|cavernas?/.test(texto)) {
      return "imagery_basemaps_earth_cover";
    }
    if (/relevo|topograf|altimet|eleva[cç][aã]o|dem\b|mde\b|mdt\b|lidar|batimetria/.test(texto) && !/geologia|minera[cç][aã]o|tecton|geofis/.test(texto)) {
      return "elevation";
    }
    return "geoscientific_information";
  }

  const highest = Object.entries(score).sort((a, b) => b[1] - a[1])[0];
  if (!highest || highest[1] <= 0) return "multitematico";
  const fallbackMap = {
    multitematico: "multitematico",
    clima_oceanos: "climatology_meteorology_atmosphere",
    geociencias_relevo: "geoscientific_information",
    preservacao_ambiental: "environment",
    agricultura_uso_solo: "farming",
    economia_trabalho: "economy",
    infraestrutura_utilidades: "utilities_communication",
    transporte_logistica: "transportation",
    defesa_inteligencia: "intelligence_military",
    planejamento_localizacao: "planning_cadastre",
    sociedade_saude: "society"
  };
  return fallbackMap[highest[0]] || "multitematico";
}

function inferirTemasAssociados(source) {
  const curadoria = obterCuradoriaTematica(source);
  if (curadoria?.temas?.length) return Array.from(new Set(curadoria.temas)).slice(0, 3);

  const { score } = pontuarTemasFonte(source);
  const ordenados = Object.entries(score)
    .filter(([, value]) => value > 0)
    .sort((a, b) => b[1] - a[1]);

  if (!ordenados.length) return ["multitematico"];

  const melhor = ordenados[0][1];
  const selecionados = ordenados
    .filter(([, value]) => value >= Math.max(2, melhor - 1))
    .slice(0, 3)
    .map(([tema]) => tema);

  if (selecionados.includes("multitematico") && selecionados.length > 1 && melhor >= 4) {
    return selecionados.filter(tema => tema !== "multitematico").slice(0, 3);
  }

  return selecionados.length ? selecionados : ["multitematico"];
}

function inferirCategoriaISO(source) {
  return inferirTemaPrincipal(source);
}

function inferirEstruturaTecnica(source) {
  const texto = obterTextoFonte(source);
  if (/wms|wfs|wmts|feature service|map service|geoserver|arcgis rest/.test(texto)) return "servico";
  if (/api|json|endpoint|api rest/.test(texto)) return "api";
  if (/csv|xlsx|xls|tabela|planilha|microdados|indicadores|serie historica|séries|series/.test(texto)) return "tabular";
  if (/pdf|relat[oó]rio|relat[oó]rios|publica[cç][aã]o|publica[cç][oõ]es|nota t[eé]cnica|documento|documentos|artigo|artigos|painel|visualizador|atlas/.test(texto)) return "nao_estruturado";
  return "geoespacial";
}

function inferirAcesso(source) {
  const texto = obterTextoFonte(source) + " " + normalizarTexto(source.url || "");
  if (/wms|wfs|wmts|feature service|map service|geoserver/.test(texto)) return "servico";
  if (/api|json|endpoint/.test(texto)) return "api";
  if (/download|downloads|dadosabertos|dados abertos|dataset|catalogo|catálogo/.test(texto)) return "download";
  return "web";
}

function inferirFormatos(source) {
  const texto = obterTextoFonte(source);
  const formatos = [];
  const candidatos = [
    ["GeoJSON", /geojson/],
    ["SHP", /shapefile|shape/],
    ["GPKG", /geopackage|gpkg/],
    ["KML/KMZ", /kml|kmz/],
    ["GeoTIFF", /geotiff|tif|tiff/],
    ["CSV", /csv/],
    ["XLSX", /xlsx|xls/],
    ["WMS", /wms/],
    ["WFS", /wfs/],
    ["WMTS", /wmts/],
    ["API", /api|json|endpoint/]
  ];

  candidatos.forEach(([label, regex]) => {
    if (regex.test(texto)) formatos.push(label);
  });

  if (!formatos.length) {
    const estrutura = source.estrutura_tecnica || inferirEstruturaTecnica(source);
    if (estrutura === "geoespacial") formatos.push("geoespacial");
    if (estrutura === "tabular") formatos.push("tabular");
    if (estrutura === "nao_estruturado") formatos.push("não estruturado");
    if (estrutura === "servico") formatos.push("serviço web");
    if (estrutura === "api") formatos.push("API");
  }

  return formatos;
}

function inferirLicenca(source) {
  const texto = obterTextoFonte(source) + " " + normalizarTexto(source.url || "");
  if (/dominio publico|public domain/.test(texto)) return "Domínio público";
  if (/open data|dados abertos|aberto|gratuito|open/.test(texto)) return "Acesso aberto, verificar termos específicos no portal";
  return "Verificar licença no portal";
}

function inferirAtualizacao(source) {
  const texto = obterTextoFonte(source);
  if (/tempo real|real time/.test(texto)) return "Tempo real ou quase real";
  if (/serie historica|série histórica|historico|histórico|1992|2020|2025|2024|2023/.test(texto)) return "Série histórica ou múltiplas edições";
  if (/atualizada continuamente|continuous|monitoramento/.test(texto)) return "Atualização contínua";
  return "Não informado no card, conferir portal";
}

function inferirResolucaoIndicativa(source) {
  const textoOriginal = [source.name || "", source.desc || "", source.meta || ""].join(" ");
  const escala = textoOriginal.match(/1:\s?[0-9\.]+/i);
  if (escala) return escala[0].replace(/\s+/g, "");
  const metros = textoOriginal.match(/\b\d+\s?(m|km)\b/i);
  if (metros) return metros[0];
  if ((source.formatos || []).includes("GeoTIFF") && source.tema_principal === "satelite") return "Raster georreferenciado, resolução variável";
  return "Não informado";
}

function inferirIndicacaoUso(source) {
  const estrutura = source.estrutura_tecnica || inferirEstruturaTecnica(source);
  const acesso = source.acesso || inferirAcesso(source);
  if (estrutura === "api") return "Integração programática, automação e consumo por scripts";
  if (estrutura === "servico") return "Consumo direto em GIS desktop, webmap ou SIG corporativo";
  if (estrutura === "tabular") return "Cruzamento com indicadores, BI e análises socioeconômicas";
  if (estrutura === "nao_estruturado") return "Consulta documental, leitura técnica, relatórios, painéis e referências";
  if (estrutura === "geoespacial") return "Mapeamento, análise espacial e integração com SIG";
  if (acesso === "download") return "Download direto para análise offline";
  return "Consulta e exploração em portal web";
}

function inferirPalavrasChave(source) {
  const base = [
    ...(source.topics || []),
    ...(source.meta || "").split("·"),
    (source.tema_principal === "society" ? "" : (source.tema_principal || "")),
    source.estrutura_tecnica || "",
    source.pais_ref || "",
    source.categoria_iso || ""
  ]
    .map(item => normalizarTexto(String(item || "")).trim())
    .filter(Boolean);

  const vistos = new Set();
  const grupos = new Set();
  return base.filter(item => {
    const grupo = canonicalTechLabel(item) || item;
    if (vistos.has(item) || grupos.has(grupo)) return false;
    vistos.add(item);
    grupos.add(grupo);
    return true;
  }).slice(0, 8).map(item => item.replaceAll("_", " "));
}


function dedupeStringArray(values) {
  const vistos = new Set();
  return (values || [])
    .map(value => String(value || "").trim())
    .filter(Boolean)
    .filter(value => {
      const chave = normalizarTexto(value);
      if (vistos.has(chave)) return false;
      vistos.add(chave);
      return true;
    });
}

// Nota para a equipa de desenvolvimento:
// Ao varrer o array JSON/JavaScript que alimenta os cards,
// removemos duplicidades em arrays de tags/labels com deduplicação explícita,
// preservando integralmente as hiperligações e URLs das fontes.

function matchesStructureFilter(itemStructure, itemTypes) {
  if (estruturaFilter === "all") return true;
  const tipos = (itemTypes || "").split(" ").filter(Boolean);
  if (estruturaFilter === "geoespacial") {
    return ["geoespacial", "vetorial", "raster"].includes(itemStructure) || tipos.includes("georreferenciado");
  }
  if (estruturaFilter === "tabular") {
    return itemStructure === "tabular" || tipos.includes("tabular");
  }
  if (estruturaFilter === "nao_estruturado") {
    return itemStructure === "nao_estruturado" || tipos.includes("nao_estruturado");
  }
  return itemStructure === estruturaFilter;
}

sources.forEach(source => {
  source.tipos_dado = dedupeStringArray([...(source.tipos_dado || []), ...inferirTiposDado(source)]);
  source.pais_ref = source.pais_ref || inferirPaisRef(source);
  source.escala = source.escala || inferirEscala(source);
  source.tema_principal = inferirTemaPrincipal(source);
  source.topics = dedupeStringArray(inferirTemasAssociados(source));
  source.estrutura_tecnica = inferirEstruturaTecnica(source);
  source.acesso = source.acesso || inferirAcesso(source);
  source.formatos = dedupeStringArray([...(source.formatos || []), ...inferirFormatos(source)]);
  source.datum = source.datum || null;
  source.crs = source.crs || null;
  source.licenca = source.licenca || inferirLicenca(source);
  source.atualizacao = source.atualizacao || inferirAtualizacao(source);
  source.resolucao_indicativa = source.resolucao_indicativa || inferirResolucaoIndicativa(source);
  source.indicacao_uso = source.indicacao_uso || inferirIndicacaoUso(source);
  source.categoria_iso = inferirCategoriaISO(source);
  source.palavras_chave = dedupeStringArray(inferirPalavrasChave(source));
  if (Array.isArray(source.tags)) source.tags = dedupeStringArray(source.tags);
  if (source.curadoria && Array.isArray(source.curadoria.temas)) source.curadoria.temas = dedupeStringArray(source.curadoria.temas);
});

