function setEscalaFilter(value) {
  escalaFilter = value;
  if (value !== "pais" && value !== "subnacional_exterior") {
    paisFilter = "all";
    const paisSelect = document.getElementById("paisFilter");
    if (paisSelect) paisSelect.value = "all";
  }
  filterCards();
}

function setTemaPrincipalFilter(value) {
  temaPrincipalFilter = value;
  activeApplicationTemaPrincipais = null;
  clearExploreOptionGroup("aplicacoes");
  filterCards();
}

function setPaisFilter(value) {
  paisFilter = value;
  filterCards();
}

function updateDynamicSelectors(queryTerm = "") {
  const paisSelect = document.getElementById("paisFilter");
  const estruturaSelect = document.getElementById("estruturaFilter");

  const pool = sources.filter(source => {
    const text = [source.name, source.desc, source.meta, (source.topics || []).join(" "), source.estrutura_tecnica, source.acesso, (source.formatos || []).join(" ")].join(" ").toLowerCase();
    const matchesTheme = !activeTheme || (source.topics || []).includes(activeTheme);
    const matchesApplicationTheme = !activeApplicationThemes || activeApplicationThemes.some(t => (source.topics || []).includes(t));
    const matchesEscala = escalaFilter === "all" || source.escala === escalaFilter;
    const matchesTema = temaPrincipalFilter === "all" || source.tema_principal === temaPrincipalFilter;
    const matchesApplicationTema = !activeApplicationTemaPrincipais || activeApplicationTemaPrincipais.includes(source.tema_principal);
    const matchesQuery = !queryTerm || text.includes(queryTerm);
    return matchesTheme && matchesApplicationTheme && matchesEscala && matchesTema && matchesApplicationTema && matchesQuery;
  });

  if (paisSelect) {
    const paises = [...new Set(sources.map(s => s.pais_ref).filter(p => p && p !== "all"))]
      .sort((a, b) => obterRotuloPais(a).localeCompare(obterRotuloPais(b), "pt-BR"));
    paisSelect.innerHTML = `<option value="all">Todos</option>` + paises.map(p => `<option value="${p}">${obterRotuloPais(p)}</option>`).join("");
    paisSelect.value = paises.includes(paisFilter) ? paisFilter : "all";
    if (paisSelect.value === "all") paisFilter = "all";
  }

  if (estruturaSelect) {
    const estruturaOrder = ["geoespacial", "tabular", "nao_estruturado", "servico", "api"];
    const estruturasPool = [...new Set(pool.map(s => s.estrutura_tecnica).filter(Boolean))];
    const estruturas = estruturaOrder.filter(value => estruturasPool.includes(value) || value === "geoespacial");
    estruturaSelect.innerHTML = `<option value="all">Todos</option>` + estruturas.map(value => `<option value="${value}">${obterRotuloEstrutura(value)}</option>`).join("");
    estruturaSelect.value = [...estruturas, "all"].includes(estruturaFilter) ? estruturaFilter : "all";
    if (estruturaSelect.value === "all") estruturaFilter = "all";
  }
}

