function getSearchStatusChips(query) {
  const chips = [];
  if (query) chips.push(`Busca: ${query}`);
  if (activeTheme) chips.push(`Tema: ${obterRotuloTemaConsolidado(activeTheme)}`);
  if (escalaFilter !== "all") chips.push(`Recorte: ${obterRotuloEscala(escalaFilter)}`);
  if (temaPrincipalFilter !== "all") chips.push(`ISO: ${obterRotuloTema(temaPrincipalFilter)}`);
  if (paisFilter !== "all") chips.push(`País: ${obterRotuloPais(paisFilter)}`);
  if (estruturaFilter !== "all") chips.push(`Estrutura: ${obterRotuloEstrutura(estruturaFilter)}`);
  return chips;
}

function updateSearchStatusBar(query, visible, total) {
  const el = document.getElementById("searchStatusBar");
  if (!el) return;

  const chips = getSearchStatusChips(query);
  const chipsHtml = chips.length
    ? chips.map(label => `<span class="active-filter-chip">${escapeHtml(label)}</span>`).join("")
    : `<span class="active-filter-chip is-neutral">Sem filtros ativos</span>`;

  el.innerHTML = `
    <div class="search-status-head">
      <strong>${visible}</strong>
      <span>fontes visíveis de ${total}</span>
    </div>
    <div class="search-status-chips">${chipsHtml}</div>
  `;
}

function toggleIsoReference() {
  const body = document.getElementById('isoRefBody');
  const btn = document.getElementById('isoToggleBtn');
  if (!body || !btn) return;
  const isHidden = body.hasAttribute('hidden');
  if (isHidden) {
    body.removeAttribute('hidden');
    btn.setAttribute('aria-expanded', 'true');
    btn.classList.add('is-open');
    btn.querySelector('span').textContent = 'Ocultar categorias ISO';
  } else {
    body.setAttribute('hidden', '');
    btn.setAttribute('aria-expanded', 'false');
    btn.classList.remove('is-open');
    btn.querySelector('span').textContent = 'Ver categorias ISO';
  }
}

function filterCards() {
  const query = document.getElementById("searchInput").value.toLowerCase().trim();
  const cards = document.querySelectorAll(".card");
  let visible = 0;

  cards.forEach(card => {
    const cat = card.dataset.cat || "";
    const name = (card.dataset.name || "").toLowerCase();
    const desc = (card.dataset.desc || "").toLowerCase();
    const meta = (card.dataset.meta || "").toLowerCase();
    const topics = (card.dataset.topics || "").split(" ").filter(Boolean);
    const escala = card.dataset.escala || "";
    const temaPrincipal = card.dataset.temaPrincipal || "";
    const pais = card.dataset.pais || "";
    const estrutura = card.dataset.estrutura || "";
    const acesso = card.dataset.acesso || "";
    const types = card.dataset.types || "";

    const expandedTerms = expandQueryTerms(query);
    const textPool = [name, desc, meta, topics.join(" "), escala, temaPrincipal, pais, estrutura, acesso, types].join(" ");

    const matchesCat = activeFilter === "all" || (activeFilter === "all_resources" ? cat === "all" : cat === activeFilter);
    const matchesQuery = !query || expandedTerms.some(term => textPool.includes(term));
    const matchesTheme = !activeTheme || topics.includes(activeTheme);
    const matchesApplicationTheme = !activeApplicationThemes || activeApplicationThemes.some(t => topics.includes(t));
    const matchesEscala = escalaFilter === "all" || escala === escalaFilter;
    const matchesTemaPrincipal = temaPrincipalFilter === "all" || temaPrincipal === temaPrincipalFilter;
    const matchesApplicationTema = !activeApplicationTemaPrincipais || activeApplicationTemaPrincipais.includes(temaPrincipal);
    const matchesPais = paisFilter === "all" || pais === paisFilter;
    const matchesEstrutura = matchesStructureFilter(estrutura, types);

    if (matchesCat && matchesQuery && matchesTheme && matchesApplicationTheme && matchesEscala && matchesTemaPrincipal && matchesApplicationTema && matchesPais && matchesEstrutura) {
      card.classList.remove("hidden");
      visible++;
    } else {
      card.classList.add("hidden");
    }
  });

  document.querySelectorAll(".section-group").forEach(group => {
    const visibleCards = group.querySelectorAll(".card:not(.hidden)");
    group.classList.toggle("hidden", visibleCards.length === 0);
  });

  const hasActiveFilter = !!query || activeTheme !== null || activeFilter !== "all" || escalaFilter !== "all" || temaPrincipalFilter !== "all" || paisFilter !== "all" || estruturaFilter !== "all";
  document.getElementById("mapa")?.classList.toggle("hidden", hasActiveFilter);

  const total = sources.length;
  updateSearchStatusBar(query, visible, total);
  document.getElementById("countDisplay").textContent = `Exibindo ${visible} de ${total} fontes`;
  document.getElementById("heroTotal").textContent = total;
  document.getElementById("statTotal").textContent = total;
  document.getElementById("noResults").style.display = visible === 0 ? "block" : "none";
  updateDynamicSelectors(query);
}

/* ====== MAPA DE ORIGENS ====== */
let sourceMapInstance = null;

function refreshSourceMap() {
  if (!sourceMapInstance) return;
  setTimeout(function() {
    try {
      sourceMapInstance.invalidateSize(true);
    } catch (e) {
      console.warn('Falha ao recalcular o mapa:', e);
    }
  }, 180);
}

